<?php declare(strict_types=1); $this->extend('layouts.admin'); $v=static fn(string $k,string $d=''):(string)=>(string)($campaign[$k]??$d); ?>
<?php $this->section('content'); ?><div class="card"><h1><?= e($title) ?></h1><p class="muted">The creative is approved when an authorised administrator saves it. Use factual copy and an HTTPS destination.</p><form method="post" action="<?= e(url('/admin/advertising/save')) ?>"><?= csrf_field() ?><input type="hidden" name="id" value="<?= (int)($campaign['id']??0) ?>"><div class="grid grid-2"><div class="form-group"><label>Advertiser business</label><input required name="business_name" value="<?= e($v('business_name')) ?>"></div><div class="form-group"><label>Contact email</label><input type="email" name="contact_email" value="<?= e($v('contact_email')) ?>"></div><div class="form-group"><label>Campaign name</label><input required name="name" value="<?= e($v('name')) ?>"></div><div class="form-group"><label>Brand</label><select name="brand_id"><?php foreach($brands as $brand): ?><option value="<?= (int)$brand['id'] ?>" <?= (int)$v('brand_id','2')===(int)$brand['id']?'selected':'' ?>><?= e($brand['name']) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Result context</label><select name="context_key"><?php foreach(['general'=>'General','mobile_weighing'=>'Mobile weighing','suspension'=>'Suspension / GVM / axle','towing_equipment'=>'Towbar / coupling / towball'] as $key=>$label): ?><option value="<?= e($key) ?>" <?= $v('context_key','general')===$key?'selected':'' ?>><?= e($label) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Status</label><select name="status"><?php foreach(['draft','pending','active','paused','completed','archived'] as $status): ?><option <?= $v('status','draft')===$status?'selected':'' ?>><?= e($status) ?></option><?php endforeach; ?></select></div><div class="form-group"><label>Starts</label><input type="datetime-local" name="starts_at" value="<?= e(str_replace(' ','T',substr($v('starts_at'),0,16))) ?>"></div><div class="form-group"><label>Ends</label><input type="datetime-local" name="ends_at" value="<?= e(str_replace(' ','T',substr($v('ends_at'),0,16))) ?>"></div><div class="form-group"><label>Priority</label><input type="number" name="priority" value="<?= e($v('priority','0')) ?>"></div><div class="form-group"><label>Label</label><input required name="sponsorship_label" value="<?= e($v('sponsorship_label','Sponsored')) ?>"></div></div><hr><div class="form-group"><label>Headline</label><input required maxlength="120" name="headline" value="<?= e($v('headline')) ?>"></div><div class="form-group"><label>Body</label><textarea required maxlength="320" name="body_text"><?= e($v('body_text')) ?></textarea></div><div class="grid grid-2"><div class="form-group"><label>Call to action</label><input maxlength="60" name="call_to_action" value="<?= e($v('call_to_action','Learn more')) ?>"></div><div class="form-group"><label>HTTPS destination</label><input required type="url" name="destination_url" value="<?= e($v('destination_url')) ?>"></div></div><div class="btn-row"><button class="btn btn-primary">Save campaign</button><a class="btn" href="<?= e(url('/admin/advertising')) ?>">Cancel</a></div></form></div><?php $this->endSection(); ?>
